            left[i] = left[i - 1] + 1;
        } else {
            left[i] = 0;
        }
    }

    // Precompute right increasing segments
    const right = new Array(n).fill(0);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right[i] = right[i + 1] + 1;
        } else {
            right[i] = 0;
        }
    }

    // Precompute decreasing segments (from left to right)
    const dec = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            dec[i] = dec[i - 1] + 1;
        } else {
            dec[i] = 0;
        }
    }

    // Iterate all possible p and q positions
