                    for (let i = q; i < r; i++) {
                        if (nums[i] >= nums[i + 1]) {
                            increasing2 = false;
                            break;
                        }
                    }
                    if (!increasing2) continue;

                    // Calculate the sum
                    let sum = 0;
                    for (let i = l; i <= r; i++) {
                        sum += nums[i];
                    }
                    if (sum > maxSum) {
                        maxSum = sum;
                    }
                }
            }
        }
    }

    return maxSum;
}
